import yaml

def normalize_key(key: str) -> str:
    # max_PSR@10kHz_range 替换为  max_psr_10khz
    key = key.replace("@", "_")
    key = key.lower().rstrip("_range")
    return key

def _load_reward_config_from_file(config_path: Optional[str] = None) -> Dict[str, Any]:
    """
    Load reward config YAML from disk (cached).
    Default path: <this_dir>/configs/acs_reward_config.yaml
    """
    return _load_reward_config_from_file_cached(
        config_path or str(Path(__file__).resolve().parent / "configs" / "acs_reward_config.yaml")
    )

def _load_reward_config_from_file_cached(config_path: str) -> Dict[str, Any]:
    with open(config_path, "r", encoding="utf-8") as f:
        data = yaml.safe_load(f) or {}
    # File format: {class_name: "...", config: {...}}
    cfg = data.get("config", {}) if isinstance(data, dict) else {}
    return cfg if isinstance(cfg, dict) else {}

def _score_maximize(value: float, min_target: float, *, threshold_ratio: float = 0.9, exponent: float = 2.0) -> float:
    """Generic score for 'larger is better' with a soft ramp below target."""
    if math.isnan(value):
        return 0.0
    threshold = abs(min_target) * threshold_ratio
    if value < min_target - threshold:
        return 0.0
    if value < min_target:
        ratio = (value - (min_target - threshold)) / threshold
        return float(ratio ** exponent)
    return 1.0

def _score_minimize(value: float, max_target: float, *, threshold_ratio: float = 9.0, exponent: float = 3.0) -> float:
    """Generic score for 'smaller is better' with a soft ramp above target."""
    if math.isnan(value):
        return 0.0
    threshold = abs(max_target) * threshold_ratio
    if value > max_target + threshold:
        return 0.0
    if value > max_target:
        ratio = (max_target + threshold - value) / threshold
        return float(ratio ** exponent)
    return 1.0

def _score_range(
    value: float,
    min_target: float,
    max_target: float,
    *,
    threshold_min_ratio: float = 0.5,
    threshold_max_ratio: float = 1.0,
    exponent_below: float = 2.0,
    exponent_above: float = 3.0,
) -> float:
    """Generic score for 'in-range is best' with soft ramps outside the range."""
    if math.isnan(value):
        return 0.0
    threshold_min = abs(min_target) * threshold_min_ratio
    threshold_max = abs(max_target) * threshold_max_ratio
    if value < min_target - threshold_min:
        return 0.0
    if value < min_target:
        ratio = (value - (min_target - threshold_min)) / threshold_min
        return float(ratio ** exponent_below)
    if value > max_target + threshold_max:
        return 0.0
    if value > max_target:
        ratio = (max_target + threshold_max - value) / threshold_max
        return float(ratio ** exponent_above)
    return 1.0

def _safe_float(d: Dict[str, Any], key: str) -> float:
    v = d.get(key, float("nan"))
    return float(v)

def _metric_score(performance: Dict[str, Any], identity: Dict[str, Any], metric: str, spec: Dict[str, Any]) -> float:
    """
    Generic metric scoring with extensible specs.
    Spec format (identity["metric_specs"] can override/extend defaults):
      - kind: "max" | "min" | "range"
      - perf_key: key in performance dict (default: metric)
      - identity_key: single key in identity (for max/min), or
      - identity_range_key: key in identity for [min,max] (for range)
      - perf_scale: multiply performance value by this (default 1.0)
      - target_scale: multiply target value(s) by this (default 1.0)
    """
    kind = spec.get("kind")
    perf_key = spec.get("perf_key", metric)
    perf_scale = float(spec.get("perf_scale", 1.0))
    target_scale = float(spec.get("target_scale", 1.0))

    v = _safe_float(performance, perf_key) * perf_scale
    if kind == "max":
        t = float(identity[normalize_key(spec["identity_key"])]) * target_scale
        return _score_maximize(v, t)
    if kind == "min":
        t = float(identity[normalize_key(spec["identity_key"])]) * target_scale
        return _score_minimize(v, t)
    if kind == "range":
        r = identity[normalize_key(spec.get("identity_range_key", spec.get("identity_key", metric)))]
        rmin, rmax = float(r[0]) * target_scale, float(r[1]) * target_scale
        return _score_range(v, rmin, rmax)
    raise KeyError(f"Unknown metric kind for {metric}: {kind}")

def _default_metric_specs() -> Dict[str, Dict[str, Any]]:
    """
    Default specs for known metrics.
    """
    return {
        # maximize
        "gain": {"kind": "max", "identity_key": "min_gain"},
        "gbw": {"kind": "max", "identity_key": "min_gbw", "target_scale": 1e6},  # MHz -> Hz
        "pm": {"kind": "max", "identity_key": "min_pm"},
        "enob": {"kind": "max", "identity_key": "min_enob"},
        "sfdr": {"kind": "max", "identity_key": "min_sfdr"},
        "snr": {"kind": "max", "identity_key": "min_snr"},
        "gm": {"kind": "max", "identity_key": "min_gm"},
        # minimize
        "pw": {"kind": "min", "identity_key": "max_power", "target_scale": 1e-6},  # μW -> W
        "irn": {"kind": "min", "identity_key": "max_irn", "target_scale": 1e-6},  # μV -> V
        "ugf": {"kind": "min", "identity_key": "max_ugf"},  # (kept as-is: existing code does not convert)
        "iq": {"kind": "min", "identity_key": "max_iq"},    # (kept as-is: existing code does not convert)
        "PSR@10Hz": {"kind": "min", "identity_key": "max_psr_10hz"},
        "PSR@10kHz": {"kind": "min", "identity_key": "max_psr_10khz"},
        "PSR_peak": {"kind": "min", "identity_key": "max_psr_peak"},
        "IdcLDO": {"kind": "min", "identity_key": "max_IdcLDO"},
        "OutNoise@1KHz": {"kind": "min", "identity_key": "max_outnoise_1khz"},
        "OutNoise@10KHz": {"kind": "min", "identity_key": "max_outnoise_10khz"},
        "OutNoise@100KHz": {"kind": "min", "identity_key": "max_outnoise_100khz"},
        "OutNoise@1MHz": {"kind": "min", "identity_key": "max_outnoise_1mhz"},
        "OutNoise@10MHz": {"kind": "min", "identity_key": "max_outnoise_10mhz"},
        "OutNoise@100MHz": {"kind": "min", "identity_key": "max_outnoise_100mhz"},
        # range
        "vout": {"kind": "range", "identity_range_key": "vout"},
    }

# 斯皮尔曼等级相关系数计算趋势得分
def compute_trend_score(rewards):
    """计算序列的增长趋势得分(0-1)"""
    # 检查是否所有奖励值都相同
    if len(set(rewards)) == 1:
        return 0.5  # 所有值相同，无趋势

    try:
        time_points = np.arange(len(rewards))
        rho, _ = spearmanr(time_points, rewards)

        # 处理NaN情况
        if np.isnan(rho):
            return 0.5

        return (rho + 1) / 2
    except:
        return 0.5  # 异常情况返回中性值

def calculate_score(performance: Dict[str, Any], identity: Dict[str, Any]) -> float:
    """
    Public scoring entrypoint for AnalogCircuitSizing.
    This is a thin wrapper around `AnalogCircuitSizingRewardCalculator._calculate_score`,
    meant for reuse by other modules (e.g., Bayesian agent evaluator/tools) without
    importing duplicate scoring logic.
    """
    return CustomAnalogCircuitSizingRewardCalculator._calculate_score(performance, identity)

class CustomAnalogCircuitSizingRewardCalculator(BaseRewardCalculator):
    """示例奖励管理器，用于评估算术运算任务"""
    def __init__(self, config: Any = None, type: str = "GM"):
        # Preferred: load from reward config file (no need to pass init params).
        # Backward compatible: if caller passes a dict, it overrides file defaults.
        file_cfg = _load_reward_config_from_file()
        self.type = file_cfg.get("type", type) if isinstance(file_cfg, dict) else type
        self.metric_specs: Dict[str, Dict[str, Any]] = (
            file_cfg.get("metric_specs", {}) if isinstance(file_cfg, dict) else {}
        )
        if isinstance(config, dict):
            # override from init if provided
            self.type = config.get("type", self.type)
            self.metric_specs = config.get("metric_specs", self.metric_specs) or {}

    def verify_score(self, model_output, identity: dict, **kwargs) -> float:
        """
        Instance entrypoint (no globals): inject default metric_specs from this instance into identity,
        but allow per-sample identity["metric_specs"] to override.
        """
        identity_dict = identity
        if isinstance(identity_dict, dict):
            merged_specs = {**(self.metric_specs or {}), **(identity_dict.get("metric_specs", {}) or {})}
            identity_dict = {**identity_dict, "metric_specs": merged_specs}
        return BaseRewardCalculator.verify_score.__func__(self.__class__, model_output, identity_dict, **kwargs)

    @staticmethod
    def extract_output(response: str) -> dict:
        # 匹配所有 "Simulation Result:" 后跟一个字典（单引号）的形式
        try:
            pattern = r"Simulation Result:\s*({'.*?'})"
            matches = re.findall(pattern, response, re.DOTALL)
            end_string = "<Design End>"


            if not matches:
                return {}
            # 取最后一个匹配
            match_num = len(matches)
            results = []

            # 安全地解析每个匹配项
            for m in matches:
                try:
                    result = ast.literal_eval(m)
                    results.append(result)
                except (SyntaxError, ValueError) as e:
                    # print(f"Error parsing simulation result: {e}")
                    continue

            if not results:  # 如果没有成功解析的结果
                return {}
            last_result = results[-1]

            format_ok = response.strip().endswith(end_string)

            # 3. 提取所有工具调用块
            tool_blocks = re.findall(r"<tool_call>\s*(\{.*?\})\s*</tool_call>", response, re.DOTALL)
            tool_call_count = len(tool_blocks)
            # 4. 按<tool_call>分割，得到间隙（模型自然语言输出）
            parts = response.split("<tool_call>")
            # parts[0]: 第一个工具调用前的文本
            # parts[1]: 第一个工具调用后的文本（含仿真结果和下一次分析）
            # ...
            # parts[N]: 最后一个工具调用后的文本（含最终结论）


            analyze_len = sum([len(part) for part in parts[:-1]])  # 忽略最后一部分（工具调用后的文本）
            analyze_ok = True
            analyze_blocks = []
            for part in parts[1:-1]:  # 忽略第一次工具调用前和最后一次工具调用后
                # 检查该部分中是否包含且仅包含一个 <Analyze>...</Analyze>
                open_count = part.count("<Analyze>")
                close_count = part.count("</Analyze>")

                if open_count != 1 or close_count != 1:
                    analyze_ok = False
                    break

                # 提取分析内容
                match = re.search(r"<Analyze>(.*?)</Analyze>", part, re.DOTALL)
                if not match:
                    analyze_ok = False
                    break
                analyze_blocks.append(match.group(1).strip())

            return {"results": results, "format_ok": format_ok, "match_num": match_num, "analyze_ok": analyze_ok, "analyze_len": analyze_len}
        except (SyntaxError, ValueError):
            return {}

    @classmethod
    def _verify_correction(cls, extracted_output, identity: dict, **kwargs) -> float:
        """
        验证用户输出并计算得分

        Args:
            extracted_output (dict): extract_output 方法返回的字典
            identity (dict): 任务信息，包含期望的性能指标: "min_gain"(dB), "min_gbw"(MHz), "max_power(μW)"， 例如{"min_gain": 75.74, "min_gbw": 0.87, "max_power": 6.31}
            eval_mode (bool): 是否为评测模式，默认为 False（训练模式）

        """
        # print(f"debug: kwargs {kwargs}")
        eval_mode = kwargs.get("eval_mode", True)
        if not extracted_output or not identity:
            return 0.0

        results = extracted_output["results"]
        format_ok = extracted_output["format_ok"] 
        match_num = extracted_output["match_num"]
        analyze_ok = extracted_output["analyze_ok"]
        analyze_len = extracted_output["analyze_len"]

        # 调用工具超出了最大轮数
        if match_num == 0 or match_num > identity["max_turn"]:
            return 0.0

        # 非评测模式下(训练) : 对格式和分析均不合格则零分
        # print(format_ok)
        # print(analyze_ok)
        if not (eval_mode==True) and (not format_ok or not analyze_ok):
            return 0.0


        # 计算得分
        if eval_mode==True:
            # 评测模式 我们只考虑最高得分
            try:
                scores = []
                for result in results:
                    s = cls._calculate_score(result, identity)
                    scores.append(s)
                score = max(scores)
                return score
            except Exception as e:
                print(f"Error calculating score: {e}")
                return 0.0
        elif eval_mode==False:
            # 非评测模式 综合考虑 最高分 平均分 以及 趋势
            try:
                scores = []
                for result in results:
                    s = cls._calculate_score(result, identity)
                    scores.append(s)
                max_score = max(scores)
                avg_score = sum(scores) / len(scores)
                trend_score = compute_trend_score(scores)
                score = (max_score + avg_score) / 2 * trend_score
                if max_score < 0.99:
                    # 未达标时，将惩罚没有调用足够多次工具的trajectory
                    score *= len(results) / identity["max_turn"]
            except Exception as e:
                print(f"Error calculating score: {e}")
                return 0.0
        elif eval_mode=="max":
            # 仅考虑最高得分
            try:
                scores = []
                for result in results:
                    s = cls._calculate_score(result, identity)
                    scores.append(s)
                score = max(scores)
            except Exception as e:
                print(f"Error calculating score: {e}")
                return 0.0
        elif eval_mode=="single-hard":
            try:
                scores = []
                for result in results:
                    s = cls._calculate_score(result, identity)
                    scores.append(s)
                if scores[-1] <= scores[0]:
                    score = 0.0
                else:
                    score = scores[-1]
            except Exception as e:
                print(f"Error calculating score: {e}")
                return 0.0
        elif eval_mode.startswith("single-minlen-"):
            try:
                min_len = int(eval_mode.split("-")[-1])
                scores = []
                for result in results:
                    s = cls._calculate_score(result, identity)
                    scores.append(s)
                if scores[-1] <= scores[0]:
                    score = 0.0
                else:
                    score = scores[-1]
                if score > 0.0:
                    # 对于有分数的回复，加入长度的权重
                    score = 0.9 * score + 0.1 * min(1.0, analyze_len / min_len)

            except Exception as e:
                print(f"Error calculating score: {e}")
                return 0.0
        else:
            assert False, f"Unknown eval_mode: {eval_mode}"
        return score

    @classmethod
    def _calculate_score(cls, performance: dict, identity: dict) -> float:
        """
        根据性能指标计算得分

        Args:
            performance (dict): {"gain": '64.8473', 'gbw': '3.24909e+10', 'pw': '8.5257e-06'} 单位分别是dB, Hz, W
            identity (dict): 任务信息，包含期望的性能指标: "min_gain"(dB), "min_gbw"(MHz), "max_power(μW)"， 例如{"min_gain": 75.74, "min_gbw": 0.87, "max_power": 6.31}
        Returns:
            float: 得分, 应是一个介于0.0到1.0之间的浮点数
        """
        targets = identity["targets"]
        try:
            if "NaN" in performance.values() or "Error" in performance or 'nan' in performance.values():
                return 0.0
            default_specs = _default_metric_specs()
            override_specs = identity.get("metric_specs", {}) or {}
            metric_specs = {**default_specs, **override_specs}
            scores = []
            scores_dict = {}
            for metric in targets:
                if metric not in metric_specs:
                    raise KeyError(
                        f"Unknown target metric: {metric}. Add it to identity['metric_specs'] "
                        f"or extend _default_metric_specs()."
                    )
                s = _metric_score(performance, identity, metric, metric_specs[metric])
                scores.append(s)
                scores_dict[metric] = s
            assert len(scores) == len(targets), "Scores length does not match targets length"
            # 几何平均保证指标均衡性
            # print(scores_dict)
            product = np.prod(scores)
            score = product ** (1/len(scores))  # n次方根归一化
            return max(0.0, min(score, 1))
        except Exception as e:
            import traceback
            traceback.print_exc()
            print(f"Error in calculate score: {e}")
            return 0.0

