    """电源抑制比评分 (越小越好)"""
    if math.isnan(psr):
        return 0.0
    threshold = abs(max_psr) * 9.0
    if psr > max_psr + threshold:
        return 0.0
    elif psr > max_psr:
        ratio = (max_psr + threshold - psr) / threshold
        return ratio ** 3
    else:
        return 1.0
def score_gm(gm, min_gm):
    """跨导评分 (越大越好)"""
    if math.isnan(gm):
        return 0.0
    threshold = abs(min_gm) * 0.9
    if gm < min_gm - threshold:
        return 0.0
    elif gm < min_gm:
        ratio = (gm - (min_gm - threshold)) / threshold
        return ratio ** 2
    else:
        return 1.0
